import 'dart:convert';

List<List<int>> chunkText(String text, int maxCodeUnits) {
  if (maxCodeUnits < 1) {
    throw ArgumentError.value(maxCodeUnits, 'maxCodeUnits');
  }
  final chunks = <List<int>>[];
  for (var offset = 0; offset < text.length; offset += maxCodeUnits) {
    final candidateEnd = offset + maxCodeUnits;
    final end = candidateEnd < text.length ? candidateEnd : text.length;
    chunks.add(utf8.encode(text.substring(offset, end)));
  }
  return chunks;
}

