import '../lib/chunk_limits.dart';
import '../lib/text_chunker.dart';
import '../lib/text_collector.dart';

void expectEqual(Object? actual, Object? expected) {
  if (actual != expected) {
    throw StateError('Expected $expected, got $actual');
  }
}

void main() {
  final chunks = chunkText('plain ascii payload', 5);
  expectEqual(collectText(chunks), 'plain ascii payload');
  expectEqual(normalizedChunkLimit(128), 128);
  expectEqual(normalizedChunkLimit(100000), 64 * 1024);
}
